1625 /// Reassociate (headermask && x) && y -> headermask && (x && y) to allow the
1626 /// header mask to be simplified further, e.g. in optimizeEVLMasks.
1627 static void reassociateHeaderMask(VPlan &Plan) {
1628   VPValue *HeaderMask = vputils::findHeaderMask(Plan);
1629   if (!HeaderMask)
1630     return;
1631   SmallVector<VPUser *> Worklist(HeaderMask->users());
1632   while (!Worklist.empty()) {
1633     auto *R = dyn_cast<VPSingleDefRecipe>(Worklist.pop_back_val());
1634     if (!R)
1635       continue;
