396 bool vputils::isUniformAcrossVFsAndUFs(VPValue *V) {
397   // Live-ins are uniform.
398   if (isa<VPIRValue, VPSymbolicValue>(V))
399     return true;
400 
401   VPRecipeBase *R = V->getDefiningRecipe();
402   VPBasicBlock *VPBB = R ? R->getParent() : nullptr;
403   VPlan *Plan = VPBB ? VPBB->getPlan() : nullptr;
404   if (VPBB &&
405       (VPBB == Plan->getVectorPreheader() || VPBB == Plan->getEntry())) {
406     if (match(V->getDefiningRecipe(),
407               m_VPInstruction<VPInstruction::CanonicalIVIncrementForPart>()))
408       return false;
409     return all_of(R->operands(), isUniformAcrossVFsAndUFs);
410   }
411 
412   if (VPRegionBlock *EnclosingRegion = VPBB->getEnclosingLoopRegion()) {
413     auto *CanonicalIV = EnclosingRegion->getCanonicalIV();
414     // Canonical IV chain is uniform.
415     if (V == CanonicalIV || V == CanonicalIV->getBackedgeValue())
416       return true;
417   }
418 
419   return TypeSwitch<const VPRecipeBase *, bool>(R)
420       .Case([](const VPDerivedIVRecipe *R) { return true; })
421       .Case([](const VPReplicateRecipe *R) {
422         // Be conservative about side-effects, except for the
423         // known-side-effecting assumes and stores, which we know will be
424         // uniform.
425         return R->isSingleScalar() &&
426                (!R->mayHaveSideEffects() ||
427                 isa<AssumeInst, StoreInst>(R->getUnderlyingInstr())) &&
428                all_of(R->operands(), isUniformAcrossVFsAndUFs);
429       })
430       .Case([](const VPWidenRecipe *R) {
431         return preservesUniformity(R->getOpcode()) &&
432                all_of(R->operands(), isUniformAcrossVFsAndUFs);
433       })
434       .Case([](const VPInstruction *VPI) {
435         return (VPI->isScalarCast() &&
436                 isUniformAcrossVFsAndUFs(VPI->getOperand(0))) ||
437                (preservesUniformity(VPI->getOpcode()) &&
438                 all_of(VPI->operands(), isUniformAcrossVFsAndUFs));
439       })
440       .Case([](const VPWidenCastRecipe *R) {
441         // A cast is uniform according to its operand.
442         return isUniformAcrossVFsAndUFs(R->getOperand(0));
443       })
444       .Default([](const VPRecipeBase *) { // A value is considered non-uniform
445                                           // unless proven otherwise.
446         return false;
447       });
448 }
