3253     /// Represents an inloop extended reduction operation, performing a
3254     /// reduction on an extended vector operand into a scalar value, and adding
3255     /// the result to a chain.
3256     ExtendedReduction,
3257     /// Represent an inloop multiply-accumulate reduction, multiplying the
3258     /// extended vector operands, performing a reduction.add on the result, and
3259     /// adding the scalar result to a chain.
3260     ExtMulAccReduction,
3261     /// Represent an inloop multiply-accumulate reduction, multiplying the
