1763 /// Try to see if all of \p Blend's masks share a common value logically and'ed
1764 /// and remove it from the masks.
1765 static void removeCommonBlendMask(VPBlendRecipe *Blend) {
1766   if (Blend->isNormalized())
1767     return;
