1861 /// Optimize the width of vector induction variables in \p Plan based on a known
1862 /// constant Trip Count, \p BestVF and \p BestUF.
1863 static bool optimizeVectorInductionWidthForTCAndVFUF(VPlan &Plan,
1864                                                      ElementCount BestVF,
1865                                                      unsigned BestUF) {
1866   // Only proceed if we have not completely removed the vector region.
1867   if (!Plan.getVectorLoopRegion())
1868     return false;
1869 
1870   const APInt *TC;
1871   if (!BestVF.isFixed() || !match(Plan.getTripCount(), m_APInt(TC)))
1872     return false;
1873 
1874   // Calculate the minimum power-of-2 bit width that can fit the known TC, VF
1875   // and UF. Returns at least 8.
1876   auto ComputeBitWidth = [](APInt TC, uint64_t Align) {
1877     APInt AlignedTC =
1878         Align * APIntOps::RoundingUDiv(TC, APInt(TC.getBitWidth(), Align),
1879                                        APInt::Rounding::UP);
1880     APInt MaxVal = AlignedTC - 1;
1881     return std::max<unsigned>(PowerOf2Ceil(MaxVal.getActiveBits()), 8);
1882   };
1883   unsigned NewBitWidth =
1884       ComputeBitWidth(*TC, BestVF.getKnownMinValue() * BestUF);
1885 
1886   LLVMContext &Ctx = Plan.getContext();
1887   auto *NewIVTy = IntegerType::get(Ctx, NewBitWidth);
1888 
1889   bool MadeChange = false;
1890 
1891   VPBasicBlock *HeaderVPBB = Plan.getVectorLoopRegion()->getEntryBasicBlock();
1892   for (VPRecipeBase &Phi : HeaderVPBB->phis()) {
1893     auto *WideIV = dyn_cast<VPWidenIntOrFpInductionRecipe>(&Phi);
1894 
1895     // Currently only handle canonical IVs as it is trivial to replace the start
1896     // and stop values, and we currently only perform the optimization when the
1897     // IV has a single use.
1898     if (!WideIV || !WideIV->isCanonical() ||
1899         WideIV->hasMoreThanOneUniqueUser() ||
1900         NewIVTy == WideIV->getScalarType())
1901       continue;
1902 
1903     // Currently only handle cases where the single user is a header-mask
1904     // comparison with the backedge-taken-count.
1905     VPUser *SingleUser = WideIV->getSingleUser();
1906     if (!SingleUser ||
1907         !match(SingleUser, m_ICmp(m_Specific(WideIV),
1908                                   m_Broadcast(m_Specific(
1909                                       Plan.getOrCreateBackedgeTakenCount())))))
1910       continue;
1911 
1912     // Update IV operands and comparison bound to use new narrower type.
1913     auto *NewStart = Plan.getConstantInt(NewIVTy, 0);
1914     WideIV->setStartValue(NewStart);
1915     auto *NewStep = Plan.getConstantInt(NewIVTy, 1);
1916     WideIV->setStepValue(NewStep);
1917 
1918     auto *NewBTC = new VPWidenCastRecipe(
1919         Instruction::Trunc, Plan.getOrCreateBackedgeTakenCount(), NewIVTy,
1920         nullptr, VPIRFlags::getDefaultFlags(Instruction::Trunc));
1921     Plan.getVectorPreheader()->appendRecipe(NewBTC);
1922     auto *Cmp = cast<VPInstruction>(WideIV->getSingleUser());
1923     Cmp->setOperand(1, NewBTC);
1924 
1925     MadeChange = true;
1926   }
1927 
1928   return MadeChange;
1929 }
