1931 /// Return true if \p Cond is known to be true for given \p BestVF and \p
1932 /// BestUF.
1933 static bool isConditionTrueViaVFAndUF(VPValue *Cond, VPlan &Plan,
1934                                       ElementCount BestVF, unsigned BestUF,
1935                                       PredicatedScalarEvolution &PSE) {
1936   if (match(Cond, m_BinaryOr(m_VPValue(), m_VPValue())))
1937     return any_of(Cond->getDefiningRecipe()->operands(), [&Plan, BestVF, BestUF,
1938                                                           &PSE](VPValue *C) {
1939       return isConditionTrueViaVFAndUF(C, Plan, BestVF, BestUF, PSE);
1940     });
1941 
1942   auto *CanIV = Plan.getVectorLoopRegion()->getCanonicalIV();
1943   if (!match(Cond, m_SpecificICmp(CmpInst::ICMP_EQ,
1944                                   m_Specific(CanIV->getBackedgeValue()),
1945                                   m_Specific(&Plan.getVectorTripCount()))))
1946     return false;
1947 
1948   // The compare checks CanIV + VFxUF == vector trip count. The vector trip
1949   // count is not conveniently available as SCEV so far, so we compare directly
1950   // against the original trip count. This is stricter than necessary, as we
1951   // will only return true if the trip count == vector trip count.
1952   const SCEV *VectorTripCount =
1953       vputils::getSCEVExprForVPValue(&Plan.getVectorTripCount(), PSE);
1954   if (isa<SCEVCouldNotCompute>(VectorTripCount))
1955     VectorTripCount = vputils::getSCEVExprForVPValue(Plan.getTripCount(), PSE);
1956   assert(!isa<SCEVCouldNotCompute>(VectorTripCount) &&
1957          "Trip count SCEV must be computable");
1958   ScalarEvolution &SE = *PSE.getSE();
1959   ElementCount NumElements = BestVF.multiplyCoefficientBy(BestUF);
1960   const SCEV *C = SE.getElementCount(VectorTripCount->getType(), NumElements);
1961   return SE.isKnownPredicate(CmpInst::ICMP_EQ, VectorTripCount, C);
1962 }
